-- =============================================
-- 04_jobs.sql
-- Inserts example jobs
-- Preconditions:
--   - Users (professors) must already exist
--   - Images must already exist (03a_images.sql) if jobs reference image_id
--   - postedBy references users.user_id (professor)
-- =============================================

-- Clean up existing jobs
DELETE
FROM jobs
WHERE job_id LIKE '00000000-0000-0000-0000-00000002%';

-- Insert example jobs
REPLACE INTO jobs (job_id,
                   professor_id,
                   research_group_id,
                   image_id,
                   subject_area,
                   research_area,
                   location,
                   workload,
                   contract_duration,
                   funding_type,
                   title,
                   job_description_en,
                   job_description_de,
                   state,
                   end_date,
                   start_date,
                   created_at,
                   last_modified_at)
